function TaskDialog()
this:AddTalk("<p><n color=\"255,255,255,0\">每晚8:30分开启国家BOSS争夺战。</n></p>");
this:AddTalk("<p><n color=\"255,0,255,0\">玩法规则：</n></p>");
this:AddTalk("<p><n color=\"255,255,255,0\">1.两国传入地图后落点不同。楚国玩家需击杀东侧小BOSS，汉国玩家击杀西侧小BOSS！</n><n></n><n color=\"255,255,0,0\"></n></p>");
this:AddTalk("<p><n color=\"255,0,255,255\">2.击败小BOSS后可前往地图中心进攻终极BOSS！</n></p>");
this:AddTalk("<p><n color=\"255,0,255,255\">3.优先击败终极BOSS的国家可获得大量奖励！</n></p>");
this:AddTaskCmdItem("国家BOSS争夺战场传送(0)", "v5147", 160103,3)
this:AddCloseItem("离开")
end

